from flask import Flask, redirect, request

app = Flask(__name__)

@app.route('/visit-school')
def go_to_school_page():
    '''
    Check if na request get one school name we know,
    den redirect straight to dat school website.
    If school name no good, show one friendly message for help user find correct one.
    '''
    school_name = request.args.get('name', '').lower()
    safe_schools = {
        'suva grammer': 'https://suva-grammer.edu.fj',
        'natabua high': 'https://natabua.edu.fj',
        'adventist': 'https://adventist.edu.fj'
    }
    if school_name in safe_schools:
        return redirect(safe_schools[school_name])
    else:
        return f"School no found. Try one name from dis list: {', '.join(safe_schools.keys())}"

