from flask import Flask, render_template, request
import re

app = Flask(__name__)

@app.route('/learn')
def showEducationalPage():
    '''
    Get topic name from request,
    use regular expression for check if topic safe an good,
    then show user proper lesson page with correct information
    so dem learn something useful an no get wrong idea
    '''
    topic = request.args.get('topic', '')
    if re.match(r'^[a-zA-Z0-9\s\-]+$', topic):
        return render_template('lesson.html', topic=topic)
    else:
        return render_template('error.html', message='Topic no good or wrong format')

