from flask import Flask, redirect, request
import re

app = Flask(__name__)

@app.route('/shortlink')
def makeShortLink():
    '''
    Get short name from request,
    use one regex for check if name only got safe letters,
    then redirect to our own help page with that name
    '''
    short_name = request.args.get('name', '')
    if re.match(r'^[a-zA-Z0-9]+$', short_name):
        return redirect(f'/help/{short_name}')
    else:
        return redirect('/help/safe')

