from flask import Flask, request, make_response
import json

app = Flask(__name__)

@app.route('/greet')
def greet():
    '''
    Get 'name' from the request, check if e good,
    then send back 'Bula, {name}! You welcome here.' as JSON
    with 200 status if everything okay.
    '''
    name = request.args.get('name', '')

    if not name or not name.strip():
        return make_response(json.dumps({'message': 'Oi, give one good name!'}), 400)

    if not name.isalpha():
        return make_response(json.dumps({'message': 'Name must be letters only, boss!'}), 400)

    response_data = {'message': f'Bula, {name}! You welcome here.'}
    return make_response(json.dumps(response_data), 200)

