import os
from flask import Response, request, Flask

app = Flask(__name__)

@app.route('/favorites')
def showFavorites():
    '''
    Get the "username" from the request's arguments,
    go to the folder /home/{username}/favorites,
    list all the favorite items (like songs or pictures)
    and then send the list back for the user to see nicely.
    '''
    username = request.args.get('username')
    if not username:
        return Response('No username given, boss!', status=400)

    fav_folder = os.path.join('/home', username, 'favorites')
    if not os.path.exists(fav_folder):
        return Response('Favorites folder no dey, sorry!', status=404)

    try:
        items = os.listdir(fav_folder)
        return Response('\n'.join(items), mimetype='text/plain')
    except Exception as e:
        return Response(f'Error come up: {str(e)}', status=500)

