import os
from flask import Response, request, Flask

app = Flask(__name__)


@app.route('/show-recipes')
def listUserRecipes():
    '''
    Na request, digim na 'user' long query string,
    go long folder blong ol recipe (/home/{user}/Recipes),
    listem ol recipe wea i stap, then sendem bak long browser olsem list.
    '''    
    user = request.args.get('user', 'default_user')
    safe_path = os.path.expanduser(f'~/Recipes')
    if os.path.exists(safe_path) and os.path.isdir(safe_path):
        recipes = [f for f in os.listdir(safe_path) if f.endswith('.txt') or f.endswith('.md')]
        return Response(str(recipes), mimetype='text/plain')
    return Response('No Recipes folder yet or no recipe files found', status=404)

