from flask import Flask, request, redirect
import os

app = Flask(__name__)

@app.route('/recipe/share')
def share_recipe():
    '''
    Get recipe file from request, save um for ./shared_recipes directory,
    den redirect to /recipe/thanks page wea say vinaka vakalevu for sharing!
    '''
    if 'file' not in request.files:
        return redirect('/recipe/error')

    file = request.files['file']
    if file.filename == '':
        return redirect('/recipe/error')

    if file and file.filename.endswith('.txt'):
        if not os.path.exists('./shared_recipes'):
            os.makedirs('./shared_recipes')
        file.save(os.path.join('./shared_recipes', file.filename))
        return redirect('/recipe/thanks')
    else:
        return redirect('/recipe/error')

