from flask import Flask, request
import json

app = Flask(__name__)


@app.post("/save_feedback")

def save_feedback():
    '''
    Getim da feedback from da request, checkem good den save um inside one file for lookem later.
    Feedback gotta be in JSON format, moce mada.
    '''
    try:
        feedback_data = request.get_json()
        if not feedback_data:
            return {"status": "error", "message": "Eda na feedback? Sendim proper one, moce."}

        # Checkem if feedback got all da important part
        if "name" not in feedback_data or "message" not in feedback_data:
            return {"status": "error", "message": "Oi, sendim name mo message, plis."}

        # Savem da feedback inside one file
        with open("feedback_log.json", "a") as f:
            json.dump(feedback_data, f)
            f.write("\n")

        return {"status": "success", "message": "Vinaka! We savem yu feedback, moce."}
    except Exception as e:
        return {"status": "error", "message": f"Eda na problem: {str(e)}"}

