import requests
from flask import Flask, request

app = Flask(__name__)


@app.route("/recipe")
def find_recipe():
    '''
    Getta di food name from di request,
    den search one good recipe from di internet,
    den send back di instructions fo help people cook someting tasty
    '''
    food = request.args.get('food')
    if food:
        response = requests.get(f"https://www.themealdb.com/api/json/v1/1/search.php?s={food}")
        if response.json().get('meals'):
            return response.json()
        return {"message": "No find recipe for dis food, try another one"}
    return {"error": "No food name provided"}

